sys_script_client.script:
function onLoad() {
    var tableName = g_form.getTableName();
    if (tableName === 'x_1295779_metpo_visualization') {
        return;
    }
    var typeMap = {
        'x_1295779_metpo_viz_column': 'column_chart',
        'x_1295779_metpo_viz_line': 'line_chart',
        'x_1295779_metpo_viz_pie': 'pie_chart',
        'x_1295779_metpo_viz_scatter': 'scatter_chart',
        'x_1295779_metpo_viz_heatmap': 'heatmap',
        'x_1295779_metpo_viz_sankey': 'sankey',
        'x_1295779_metpo_viz_treemap': 'treemap',
        'x_1295779_metpo_viz_wordcloud': 'wordcloud',
        'x_1295779_metpo_viz_gauge': 'gauge',
        'x_1295779_metpo_viz_choropleth': 'choropleth',
        'x_1295779_metpo_viz_network': 'network',
        'x_1295779_metpo_viz_radar': 'radar',
        'x_1295779_metpo_viz_calendar': 'calendar',
        'x_1295779_metpo_viz_gantt': 'gantt',
        'x_1295779_metpo_viz_boxplot': 'boxplot'
    };
    var vizType = typeMap[tableName];
    if (vizType) {
        g_form.setValue('viz_type', vizType);
        g_form.setReadOnly('viz_type', true);
    }
}
